import React from "react";

export default function MessageBubble({ sender, text, time, isSelf }) {
  return (
    <div className={`flex ${isSelf ? "justify-end" : "justify-start"} mb-2`}>
      <div
        className={`max-w-[70%] px-4 py-2 rounded-lg shadow-md ${
          isSelf
            ? "bg-blue-500 text-white rounded-br-none"
            : "bg-gray-200 text-gray-800 rounded-bl-none"
        }`}
      >
        <div className="text-sm font-semibold">{sender}</div>
        <div className="text-base">{text}</div>
        <div className="text-xs text-right text-gray-300 mt-1">{time}</div>
      </div>
    </div>
  );
}
